const USERNAME = "nam"; // 這裡讓我以后可以自己改帳號
const PASSWORD = "0000"; // 這裡讓我以后可以自己改密碼
// ============================================================

const COOKIE_NAME = "disk_auth_v2";
const COOKIE_MAX_AGE = 30 * 24 * 60 * 60; // 30 天

// 創建認證 Token
async function createAuthToken(username, password) {
  const encoder = new TextEncoder();
  const key = await crypto.subtle.importKey(
    "raw",
    encoder.encode(password),
    { name: "HMAC", hash: "SHA-256" },
    false,
    ["sign"]
  );
  const sig = await crypto.subtle.sign("HMAC", key, encoder.encode(username + ":private_drive_v2"));
  return btoa(String.fromCharCode(...new Uint8Array(sig)));
}

// 獲取 Cookie
function getCookie(request, name) {
  const cookieHeader = request.headers.get("Cookie") || "";
  for (const part of cookieHeader.split(";")) {
    const [key, ...rest] = part.trim().split("=");
    if (key === name) return rest.join("=");
  }
  return null;
}

// 檢查是否已登入
async function isLoggedIn(request) {
  const token = getCookie(request, COOKIE_NAME);
  if (!token) return false;
  const expected = await createAuthToken(USERNAME, PASSWORD);
  return token === expected;
}

// 構建 Cookie
// 構建 Cookie（本地開發時不设置 HttpOnly 和 Secure）
function buildAuthCookie(token, isLocal = false) {
  if (isLocal) {
    return `${COOKIE_NAME}=${token}; Path=/; Max-Age=${COOKIE_MAX_AGE}`;
  }
  return `${COOKIE_NAME}=${token}; Path=/; Max-Age=${COOKIE_MAX_AGE}; HttpOnly; Secure; SameSite=Strict`;
}

