// 格式化日期時間
function formatDate(dateStr) {
  if (!dateStr) return '-';
  const date = new Date(dateStr);
  const now = new Date();
  const diff = now - date;
  
  // 24小時內
  if (diff < 86400000 && date.getDate() === now.getDate()) {
    return '今天 ' + date.toLocaleTimeString('zh-HK', { hour: '2-digit', minute: '2-digit' });
  }
  // 昨天
  const yesterday = new Date(now);
  yesterday.setDate(yesterday.getDate() - 1);
  if (date.getDate() === yesterday.getDate() && date.getMonth() === yesterday.getMonth()) {
    return '昨天 ' + date.toLocaleTimeString('zh-HK', { hour: '2-digit', minute: '2-digit' });
  }
  // 本年
  if (date.getFullYear() === now.getFullYear()) {
    return date.toLocaleDateString('zh-HK', { month: 'short', day: 'numeric' }) + ' ' + 
           date.toLocaleTimeString('zh-HK', { hour: '2-digit', minute: '2-digit' });
  }
  // 其他
  return date.toLocaleDateString('zh-HK', { year: 'numeric', month: 'short', day: 'numeric' });
}

